  8→function sanitizeFileName(name = 'sheet') {
  9→  return name
 10→    .trim()
 11→    .replace(/[<>:"/\\|?*\x00-\x1F]/g, '-')
 12→    .replace(/\s+/g, ' ')
 13→    .slice(0, 120)
 14→    || 'sheet';
