 17→function downloadBlob(blob, fileName) {
 18→  const url = URL.createObjectURL(blob);
 19→  const link = document.createElement('a');
 20→  link.href = url;
 21→  link.download = fileName;
 22→  document.body.appendChild(link);
 23→  link.click();
 24→  link.remove();
 25→  window.setTimeout(() => URL.revokeObjectURL(url), 1000);
 26→}
