 28→function applyComputedSvgStyle(sourceElement, targetElement) {
 29→  const style = window.getComputedStyle(sourceElement);
 30→  const properties = [
 31→    'fill',
 32→    'fill-opacity',
 33→    'stroke',
 34→    'stroke-opacity',
 35→    'stroke-width',
 36→    'stroke-linecap',
 37→    'stroke-linejoin',
 38→    'stroke-dasharray',
 39→    'opacity',
 40→    'font-size',
 41→    'font-family',
 42→    'font-weight',
 43→    'letter-spacing',
 44→    'text-anchor',
 45→    'dominant-baseline',
 46→  ];
 47→
 48→  for (const property of properties) {
 49→    const value = style.getPropertyValue(property);
 50→    if (value) {
 51→      targetElement.style.setProperty(property, value);
 52→    }
 53→  }
 54→}
 55→
 56→function inlineComputedStyles(sourceRoot, clonedRoot) {
 57→  const sourceNodes = [sourceRoot, ...sourceRoot.querySelectorAll('*')];
 58→  const clonedNodes = [clonedRoot, ...clonedRoot.querySelectorAll('*')];
 59→
 60→  for (let index = 0; index < sourceNodes.length; index += 1) {
 61→    applyComputedSvgStyle(sourceNodes[index], clonedNodes[index]);
 62→  }
 63→}
