117→function getExportSvg() {
118→  return document.querySelector('[data-sheet-export-root="true"]');
119→}
120→
121→function fmt(value) {
122→  const number = Number(value) || 0;
123→  return Math.abs(number) < 1e-8 ? '0' : number.toFixed(3).replace(/\.?0+$/, '');
124→}
125→
126→function escapePdfText(value = '') {
127→  return String(value)
128→    .replace(/[^\x20-\x7E]/g, '?')
129→    .replace(/\\/g, '\\\\')
130→    .replace(/\(/g, '\\(')
131→    .replace(/\)/g, '\\)');
132→}
133→
134→function parseNumberList(value = '') {
135→  const matches = String(value).match(/-?\d*\.?\d+(?:e[-+]?\d+)?/gi);
136→  return matches ? matches.map(Number) : [];
137→}
138→
139→function parsePoints(points = '') {
140→  const values = parseNumberList(points);
141→  const result = [];
142→  for (let index = 0; index < values.length; index += 2) {
143→    result.push({ x: values[index], y: values[index + 1] });
144→  }
145→  return result;
146→}
147→
148→function parseTransform(transform = '') {
149→  let matrix = new DOMMatrix();
150→  const pattern = /([a-zA-Z]+)\(([^)]*)\)/g;
151→  let match = pattern.exec(transform);
152→  while (match) {
153→    const [, name, argsString] = match;
154→    const args = parseNumberList(argsString);
155→    switch (name) {
156→      case 'translate':
157→        matrix = matrix.multiply(new DOMMatrix().translate(args[0] || 0, args[1] || 0));
158→        break;
159→      case 'scale':
160→        matrix = matrix.multiply(new DOMMatrix().scale(args[0] ?? 1, args[1] ?? args[0] ?? 1));
161→        break;
162→      case 'rotate':
163→        if (args.length >= 3) {
164→          matrix = matrix.multiply(new DOMMatrix().translate(args[1], args[2]).rotate(args[0]).translate(-args[1], -args[2]));
165→        } else {
166→          matrix = matrix.multiply(new DOMMatrix().rotate(args[0] || 0));
167→        }
168→        break;
169→      case 'matrix':
170→        if (args.length >= 6) {
171→          matrix = matrix.multiply(new DOMMatrix([args[0], args[1], args[2], args[3], args[4], args[5]]));
172→        }
173→        break;
174→      default:
175→        break;
176→    }
177→    match = pattern.exec(transform);
178→  }
179→  return matrix;
180→}
181→
182→function matrixIsIdentity(matrix) {
183→  return (
184→    Math.abs(matrix.a - 1) < 1e-8
185→    && Math.abs(matrix.b) < 1e-8
186→    && Math.abs(matrix.c) < 1e-8
187→    && Math.abs(matrix.d - 1) < 1e-8
188→    && Math.abs(matrix.e) < 1e-8
189→    && Math.abs(matrix.f) < 1e-8
190→  );
191→}
192→
193→function parseViewBox(svgElement) {
194→  const values = parseNumberList(svgElement.getAttribute('viewBox') || '');
195→  if (values.length !== 4) {
196→    return {
197→      minX: 0,
198→      minY: 0,
199→      width: Number(svgElement.getAttribute('width')) || 0,
200→      height: Number(svgElement.getAttribute('height')) || 0,
201→    };
202→  }
203→  return {
204→    minX: values[0],
205→    minY: values[1],
206→    width: values[2],
207→    height: values[3],
208→  };
209→}
210→
211→function getLocalMatrix(element) {
212→  const transformAttr = element.getAttribute('transform') || '';
213→  let matrix = new DOMMatrix();
214→
215→  if (element.tagName.toLowerCase() === 'svg') {
216→    const x = Number(element.getAttribute('x')) || 0;
217→    const y = Number(element.getAttribute('y')) || 0;
218→    const width = Number(element.getAttribute('width')) || 0;
219→    const height = Number(element.getAttribute('height')) || 0;
220→    const viewBox = parseViewBox(element);
221→    const scaleX = viewBox.width ? width / viewBox.width : 1;
222→    const scaleY = viewBox.height ? height / viewBox.height : 1;
223→    matrix = matrix
224→      .translate(x, y)
225→      .scale(scaleX || 1, scaleY || 1)
226→      .translate(-viewBox.minX, -viewBox.minY);
227→  }
228→
229→  if (transformAttr) {
230→    matrix = matrix.multiply(parseTransform(transformAttr));
231→  }
232→
233→  return matrix;
234→}
235→
236→function parseColor(styleValue) {
237→  if (!styleValue || styleValue === 'none') return null;
238→  const normalized = String(styleValue).trim();
239→
240→  if (normalized.startsWith('#')) {
241→    const hex = normalized.slice(1);
242→    const chunks = hex.length === 3
243→      ? hex.split('').map((value) => value + value)
244→      : [hex.slice(0, 2), hex.slice(2, 4), hex.slice(4, 6)];
245→    return chunks.map((value) => parseInt(value, 16) / 255);
246→  }
247→
248→  const rgb = normalized.match(/rgba?\(([^)]+)\)/i);
249→  if (rgb) {
250→    const values = rgb[1].split(',').map((value) => Number.parseFloat(value.trim()));
251→    return values.slice(0, 3).map((value) => value / 255);
252→  }
253→
254→  return null;
255→}
256→
257→function computeStyle(element) {
258→  const style = window.getComputedStyle(element);
259→  const fill = parseColor(style.fill);
260→  const stroke = parseColor(style.stroke);
261→  const strokeWidth = Number.parseFloat(style.strokeWidth) || 0;
262→  const lineCap = style.strokeLinecap || 'butt';
263→  const lineJoin = style.strokeLinejoin || 'miter';
264→  const dashArray = parseNumberList(style.strokeDasharray || '');
265→  const fontSize = Number.parseFloat(style.fontSize) || 12;
266→  const opacity = Number.parseFloat(style.opacity || '1') || 1;
267→  const fillOpacity = fill ? opacity * (Number.parseFloat(style.fillOpacity || '1') || 1) : 0;
268→  const strokeOpacity = stroke ? opacity * (Number.parseFloat(style.strokeOpacity || '1') || 1) : 0;
269→
270→  return {
271→    fill,
272→    stroke,
273→    strokeWidth,
274→    lineCap,
275→    lineJoin,
276→    dashArray,
277→    fontSize,
278→    fontFamily: style.fontFamily || 'Arial',
279→    fontWeight: style.fontWeight || '400',
280→    textAnchor: style.textAnchor || 'start',
281→    dominantBaseline: style.dominantBaseline || 'auto',
282→    fillOpacity,
283→    strokeOpacity,
284→  };
285→}
286→
287→function lineCapCode(value) {
288→  if (value === 'round') return 1;
289→  if (value === 'square') return 2;
290→  return 0;
291→}
292→
293→function lineJoinCode(value) {
294→  if (value === 'round') return 1;
295→  if (value === 'bevel') return 2;
296→  return 0;
297→}
298→
299→function normalizeSweep(delta, sweepFlag) {
300→  let result = delta;
301→  if (sweepFlag && result < 0) result += Math.PI * 2;
302→  if (!sweepFlag && result > 0) result -= Math.PI * 2;
303→  return result;
304→}
305→
306→function buildArcPoints(start, rx, ry, rotation, largeArcFlag, sweepFlag, end) {
307→  if (!start || !end) return [end];
308→  if (Math.abs(rotation) > 1e-6 || Math.abs(rx - ry) > 1e-6) return [end];
309→  const radius = Math.abs(rx);
310→  const dx = end.x - start.x;
311→  const dy = end.y - start.y;
312→  const chordLength = Math.hypot(dx, dy);
313→  if (chordLength < 1e-6 || radius < chordLength / 2) return [end];
314→
315→  const midX = (start.x + end.x) / 2;
316→  const midY = (start.y + end.y) / 2;
317→  const halfChord = chordLength / 2;
318→  const offsetLength = Math.sqrt(Math.max(0, radius * radius - halfChord * halfChord));
319→  const ux = -dy / chordLength;
320→  const uy = dx / chordLength;
321→
322→  const centers = [
323→    { x: midX + ux * offsetLength, y: midY + uy * offsetLength },
324→    { x: midX - ux * offsetLength, y: midY - uy * offsetLength },
325→  ];
326→
327→  for (const center of centers) {
328→    const startAngle = Math.atan2(start.y - center.y, start.x - center.x);
329→    const endAngle = Math.atan2(end.y - center.y, end.x - center.x);
330→    const sweepDelta = normalizeSweep(endAngle - startAngle, Boolean(sweepFlag));
331→    const isLarge = Math.abs(sweepDelta) > Math.PI;
332→    if (isLarge !== Boolean(largeArcFlag)) continue;
333→
334→    const points = [];
335→    for (let index = 1; index <= ARC_SEGMENTS; index += 1) {
336→      const angle = startAngle + (sweepDelta * index) / ARC_SEGMENTS;
337→      points.push({
338→        x: center.x + radius * Math.cos(angle),
339→        y: center.y + radius * Math.sin(angle),
340→      });
341→    }
342→    return points;
343→  }
344→
345→  return [end];
346→}
347→
348→function parsePathData(pathData = '') {
349→  const tokens = String(pathData).match(/[AaCcHhLlMmQqSsTtVvZz]|-?\d*\.?\d+(?:e[-+]?\d+)?/g) || [];
350→  const commands = [];
351→  let index = 0;
352→  let current = { x: 0, y: 0 };
353→  let subpathStart = { x: 0, y: 0 };
354→  let command = null;
355→
356→  const nextNumber = () => Number(tokens[index++]);
357→  const hasNumber = () => index < tokens.length && !/^[A-Za-z]$/.test(tokens[index]);
358→
359→  while (index < tokens.length) {
360→    if (/^[A-Za-z]$/.test(tokens[index])) {
361→      command = tokens[index++];
362→    }
363→    if (!command) break;
364→
365→    switch (command) {
366→      case 'M':
367→      case 'm': {
368→        while (hasNumber()) {
369→          const x = nextNumber();
370→          const y = nextNumber();
371→          current = command === 'm'
372→            ? { x: current.x + x, y: current.y + y }
373→            : { x, y };
374→          commands.push({ type: 'M', x: current.x, y: current.y });
375→          subpathStart = { ...current };
376→          command = command === 'm' ? 'l' : 'L';
377→        }
378→        break;
379→      }
380→      case 'L':
381→      case 'l':
382→        while (hasNumber()) {
383→          const x = nextNumber();
384→          const y = nextNumber();
385→          current = command === 'l'
386→            ? { x: current.x + x, y: current.y + y }
387→            : { x, y };
388→          commands.push({ type: 'L', x: current.x, y: current.y });
389→        }
390→        break;
391→      case 'H':
392→      case 'h':
393→        while (hasNumber()) {
394→          const x = nextNumber();
395→          current = command === 'h'
396→            ? { x: current.x + x, y: current.y }
397→            : { x, y: current.y };
398→          commands.push({ type: 'L', x: current.x, y: current.y });
399→        }
400→        break;
401→      case 'V':
402→      case 'v':
403→        while (hasNumber()) {
404→          const y = nextNumber();
405→          current = command === 'v'
406→            ? { x: current.x, y: current.y + y }
407→            : { x: current.x, y };
408→          commands.push({ type: 'L', x: current.x, y: current.y });
409→        }
410→        break;
411→      case 'A':
412→      case 'a':
413→        while (hasNumber()) {
414→          const rx = nextNumber();
415→          const ry = nextNumber();
416→          const rotation = nextNumber();
417→          const largeArcFlag = nextNumber();
418→          const sweepFlag = nextNumber();
419→          const xValue = nextNumber();
420→          const yValue = nextNumber();
421→          const end = command === 'a'
422→            ? { x: current.x + xValue, y: current.y + yValue }
423→            : { x: xValue, y: yValue };
424→          const arcPoints = buildArcPoints(current, rx, ry, rotation, largeArcFlag, sweepFlag, end);
425→          for (const point of arcPoints) {
426→            commands.push({ type: 'L', x: point.x, y: point.y });
427→          }
428→          current = end;
429→        }
430→        break;
431→      case 'Z':
432→      case 'z':
433→        commands.push({ type: 'Z' });
434→        current = { ...subpathStart };
435→        break;
436→      default:
437→        index = tokens.length;
438→        break;
439→    }
440→  }
441→
442→  return commands;
443→}
444→
445→function emitPathFromPoints(builder, points, closePath) {
446→  if (!points.length) return;
447→  builder.write(`${fmt(points[0].x)} ${fmt(points[0].y)} m`);
448→  for (let index = 1; index < points.length; index += 1) {
449→    builder.write(`${fmt(points[index].x)} ${fmt(points[index].y)} l`);
450→  }
451→  if (closePath) builder.write('h');
452→}
