568→function beginNode(builder, element) {
569→  const localMatrix = getLocalMatrix(element);
570→  const tagName = element.tagName.toLowerCase();
571→  const needsClip = tagName === 'svg' && element !== getExportSvg();
572→  const shouldWrap = needsClip || !matrixIsIdentity(localMatrix);
573→
574→  if (!shouldWrap) return false;
575→
576→  builder.write('q');
577→  if (!matrixIsIdentity(localMatrix)) {
578→    builder.write(`${fmt(localMatrix.a)} ${fmt(localMatrix.b)} ${fmt(localMatrix.c)} ${fmt(localMatrix.d)} ${fmt(localMatrix.e)} ${fmt(localMatrix.f)} cm`);
579→  }
580→
581→  if (needsClip) {
582→    const width = Number(element.getAttribute('width')) || 0;
583→    const height = Number(element.getAttribute('height')) || 0;
584→    builder.write(`0 0 ${fmt(width)} ${fmt(height)} re W n`);
585→  }
586→
587→  return true;
588→}
589→
590→function endNode(builder, wrapped) {
591→  if (wrapped) {
592→    builder.write('Q');
593→  }
594→}
595→
596→function beginCanvasNode(context, element) {
597→  const localMatrix = getLocalMatrix(element);
598→  const tagName = element.tagName.toLowerCase();
599→  const needsClip = tagName === 'svg' && element !== getExportSvg();
600→
601→  context.save();
602→  if (!matrixIsIdentity(localMatrix)) {
603→    context.transform(
604→      localMatrix.a,
605→      localMatrix.b,
606→      localMatrix.c,
607→      localMatrix.d,
608→      localMatrix.e,
609→      localMatrix.f
610→    );
611→  }
612→
613→  if (needsClip) {
614→    const width = Number(element.getAttribute('width')) || 0;
615→    const height = Number(element.getAttribute('height')) || 0;
616→    context.beginPath();
617→    context.rect(0, 0, width, height);
618→    context.clip();
619→  }
620→}
621→
622→function endCanvasNode(context) {
623→  context.restore();
624→}
625→
626→function applyCanvasStyle(context, style) {
627→  if (style.fill) {
628→    context.fillStyle = `rgb(${Math.round(style.fill[0] * 255)}, ${Math.round(style.fill[1] * 255)}, ${Math.round(style.fill[2] * 255)})`;
629→  }
630→  if (style.stroke && style.strokeWidth > 0) {
631→    context.strokeStyle = `rgb(${Math.round(style.stroke[0] * 255)}, ${Math.round(style.stroke[1] * 255)}, ${Math.round(style.stroke[2] * 255)})`;
632→    context.lineWidth = style.strokeWidth;
633→    context.lineCap = style.lineCap || 'butt';
634→    context.lineJoin = style.lineJoin || 'miter';
635→    context.setLineDash(style.dashArray || []);
636→  } else {
637→    context.setLineDash([]);
638→  }
639→}
640→
641→function fillAndStrokeCanvasPath(context, style) {
642→  const hasFill = Boolean(style.fill);
643→  const hasStroke = Boolean(style.stroke && style.strokeWidth > 0);
644→
645→  if (hasFill) {
646→    context.globalAlpha = style.fillOpacity;
647→    context.fill();
648→  }
649→  if (hasStroke) {
650→    context.globalAlpha = style.strokeOpacity;
651→    context.stroke();
652→  }
653→  context.globalAlpha = 1;
654→}
655→
656→function drawRectToCanvas(context, element) {
657→  const style = computeStyle(element);
658→  const x = Number(element.getAttribute('x')) || 0;
659→  const y = Number(element.getAttribute('y')) || 0;
660→  const width = Number(element.getAttribute('width')) || 0;
661→  const height = Number(element.getAttribute('height')) || 0;
662→
663→  context.save();
664→  applyCanvasStyle(context, style);
665→  context.beginPath();
666→  context.rect(x, y, width, height);
667→  fillAndStrokeCanvasPath(context, style);
668→  context.restore();
669→}
670→
671→function drawLineToCanvas(context, element) {
672→  const style = computeStyle(element);
673→  if (!style.stroke || style.strokeWidth <= 0) return;
674→
675→  context.save();
676→  applyCanvasStyle(context, style);
677→  context.globalAlpha = style.strokeOpacity;
678→  context.beginPath();
679→  context.moveTo(Number(element.getAttribute('x1')) || 0, Number(element.getAttribute('y1')) || 0);
680→  context.lineTo(Number(element.getAttribute('x2')) || 0, Number(element.getAttribute('y2')) || 0);
681→  context.stroke();
682→  context.restore();
683→}
684→
685→function drawPolygonToCanvas(context, element, closePath) {
686→  const style = computeStyle(element);
687→  const points = parsePoints(element.getAttribute('points') || '');
688→  if (!points.length) return;
689→
690→  context.save();
691→  applyCanvasStyle(context, style);
692→  context.beginPath();
693→  context.moveTo(points[0].x, points[0].y);
694→  for (let index = 1; index < points.length; index += 1) {
695→    context.lineTo(points[index].x, points[index].y);
696→  }
697→  if (closePath) context.closePath();
698→  fillAndStrokeCanvasPath(context, style);
699→  context.restore();
700→}
701→
702→function drawPathToCanvas(context, element) {
703→  const style = computeStyle(element);
704→  const commands = parsePathData(element.getAttribute('d') || '');
705→  if (!commands.length) return;
706→
707→  context.save();
708→  applyCanvasStyle(context, style);
709→  context.beginPath();
710→  for (const command of commands) {
711→    if (command.type === 'M') context.moveTo(command.x, command.y);
712→    else if (command.type === 'L') context.lineTo(command.x, command.y);
713→    else if (command.type === 'Z') context.closePath();
714→  }
715→  fillAndStrokeCanvasPath(context, style);
716→  context.restore();
717→}
718→
719→function drawTextToCanvas(context, element) {
720→  const style = computeStyle(element);
721→  if (!style.fill) return;
722→
723→  context.save();
724→  context.fillStyle = `rgb(${Math.round(style.fill[0] * 255)}, ${Math.round(style.fill[1] * 255)}, ${Math.round(style.fill[2] * 255)})`;
725→  context.globalAlpha = style.fillOpacity;
726→  context.font = `${style.fontWeight} ${style.fontSize}px ${style.fontFamily}`;
727→  context.textAlign = style.textAnchor === 'middle' ? 'center' : style.textAnchor === 'end' ? 'right' : 'left';
728→  context.textBaseline = style.dominantBaseline === 'middle' ? 'middle' : 'alphabetic';
729→
730→  const lines = getTextLines(element);
731→  for (const line of lines) {
732→    context.fillText(line.text, line.x, line.y);
733→  }
734→
735→  context.restore();
736→}
737→
738→function drawElementToCanvas(context, element) {
739→  const tagName = element.tagName.toLowerCase();
740→  beginCanvasNode(context, element);
741→
742→  switch (tagName) {
743→    case 'svg':
744→    case 'g':
745→      [...element.children].forEach((child) => drawElementToCanvas(context, child));
746→      break;
747→    case 'rect':
748→      drawRectToCanvas(context, element);
749→      break;
750→    case 'line':
751→      drawLineToCanvas(context, element);
752→      break;
753→    case 'polygon':
754→      drawPolygonToCanvas(context, element, true);
755→      break;
756→    case 'polyline':
757→      drawPolygonToCanvas(context, element, false);
758→      break;
759→    case 'path':
760→      drawPathToCanvas(context, element);
761→      break;
762→    case 'text':
763→      drawTextToCanvas(context, element);
764→      break;
765→    default:
766→      [...element.children].forEach((child) => drawElementToCanvas(context, child));
767→      break;
768→  }
769→
770→  endCanvasNode(context);
771→}
772→
773→function renderPolygonLike(builder, element, closePath) {
774→  const points = parsePoints(element.getAttribute('points') || '');
775→  if (!points.length) return;
776→  const style = computeStyle(element);
777→  builder.write('q');
778→  builder.applyStyle(style);
779→  emitPathFromPoints(builder, points, closePath);
780→
781→  if (style.fill && style.stroke && style.strokeWidth > 0) builder.write('B');
782→  else if (style.fill) builder.write('f');
783→  else if (style.stroke && style.strokeWidth > 0) builder.write('S');
784→  builder.write('Q');
785→}
786→
787→function renderRect(builder, element) {
788→  const x = Number(element.getAttribute('x')) || 0;
789→  const y = Number(element.getAttribute('y')) || 0;
790→  const width = Number(element.getAttribute('width')) || 0;
791→  const height = Number(element.getAttribute('height')) || 0;
792→  const style = computeStyle(element);
793→
794→  builder.write('q');
795→  builder.applyStyle(style);
796→  builder.write(`${fmt(x)} ${fmt(y)} ${fmt(width)} ${fmt(height)} re`);
797→  if (style.fill && style.stroke && style.strokeWidth > 0) builder.write('B');
798→  else if (style.fill) builder.write('f');
799→  else if (style.stroke && style.strokeWidth > 0) builder.write('S');
800→  builder.write('Q');
801→}
802→
803→function renderLine(builder, element) {
804→  const x1 = Number(element.getAttribute('x1')) || 0;
805→  const y1 = Number(element.getAttribute('y1')) || 0;
806→  const x2 = Number(element.getAttribute('x2')) || 0;
807→  const y2 = Number(element.getAttribute('y2')) || 0;
808→  const style = computeStyle(element);
809→  if (!style.stroke || style.strokeWidth <= 0) return;
810→
811→  builder.write('q');
812→  builder.applyStyle(style, { fillAllowed: false, strokeAllowed: true });
813→  builder.write(`${fmt(x1)} ${fmt(y1)} m`);
814→  builder.write(`${fmt(x2)} ${fmt(y2)} l`);
815→  builder.write('S');
816→  builder.write('Q');
817→}
818→
819→function renderPath(builder, element) {
820→  const commands = parsePathData(element.getAttribute('d') || '');
821→  if (!commands.length) return;
822→  const style = computeStyle(element);
823→
824→  builder.write('q');
825→  builder.applyStyle(style);
826→  for (const command of commands) {
827→    if (command.type === 'M') builder.write(`${fmt(command.x)} ${fmt(command.y)} m`);
828→    else if (command.type === 'L') builder.write(`${fmt(command.x)} ${fmt(command.y)} l`);
829→    else if (command.type === 'Z') builder.write('h');
830→  }
831→
832→  if (style.fill && style.stroke && style.strokeWidth > 0) builder.write('B');
833→  else if (style.fill) builder.write('f');
834→  else if (style.stroke && style.strokeWidth > 0) builder.write('S');
835→  builder.write('Q');
836→}
837→
838→function estimateTextWidth(text, fontSize) {
839→  return text.length * fontSize * 0.56;
840→}
841→
842→function renderTextLine(builder, text, x, y, style) {
843→  if (!text) return;
844→  let drawX = x;
845→  const textWidth = estimateTextWidth(text, style.fontSize);
846→  if (style.textAnchor === 'middle') drawX -= textWidth / 2;
847→  else if (style.textAnchor === 'end') drawX -= textWidth;
848→
849→  let baselineY = y;
850→  if (style.dominantBaseline === 'middle') {
851→    baselineY += style.fontSize * 0.32;
852→  }
853→
854→  builder.write('q');
855→  builder.applyStyle(style, { fillAllowed: true, strokeAllowed: false });
856→  builder.write('BT');
857→  builder.write(`/F1 ${fmt(style.fontSize)} Tf`);
858→  builder.write(`1 0 0 -1 ${fmt(drawX)} ${fmt(baselineY)} Tm`);
859→  builder.write(`(${escapePdfText(text)}) Tj`);
860→  builder.write('ET');
861→  builder.write('Q');
862→}
863→
864→function getTextLines(element) {
865→  const x = Number(element.getAttribute('x')) || 0;
866→  const y = Number(element.getAttribute('y')) || 0;
867→  const tspans = [...element.children].filter((child) => child.tagName?.toLowerCase() === 'tspan');
868→
869→  if (!tspans.length) {
870→    return [{ text: element.textContent || '', x, y }];
871→  }
872→
873→  let currentY = y;
874→  return tspans.map((tspan, index) => {
875→    const text = tspan.textContent || '';
876→    const lineX = tspan.hasAttribute('x') ? Number(tspan.getAttribute('x')) : x;
877→    if (tspan.hasAttribute('y')) {
878→      currentY = Number(tspan.getAttribute('y'));
879→    } else if (tspan.hasAttribute('dy')) {
880→      currentY += Number(tspan.getAttribute('dy'));
881→    } else if (index > 0) {
882→      currentY = y;
883→    }
884→    return { text, x: lineX, y: currentY };
885→  });
886→}
887→
888→function renderText(builder, element) {
889→  const style = computeStyle(element);
890→  if (!style.fill) return;
891→  const lines = getTextLines(element);
892→  lines.forEach((line) => renderTextLine(builder, line.text, line.x, line.y, style));
893→}
894→
895→function walkElement(builder, element) {
896→  const tagName = element.tagName.toLowerCase();
897→  const wrapped = beginNode(builder, element);
898→
899→  switch (tagName) {
900→    case 'svg':
901→    case 'g':
902→      [...element.children].forEach((child) => walkElement(builder, child));
903→      break;
904→    case 'rect':
905→      renderRect(builder, element);
906→      break;
907→    case 'line':
908→      renderLine(builder, element);
909→      break;
910→    case 'polygon':
911→      renderPolygonLike(builder, element, true);
912→      break;
913→    case 'polyline':
914→      renderPolygonLike(builder, element, false);
915→      break;
916→    case 'path':
917→      renderPath(builder, element);
918→      break;
919→    case 'text':
920→      renderText(builder, element);
921→      break;
922→    default:
923→      [...element.children].forEach((child) => walkElement(builder, child));
924→      break;
925→  }
926→
927→  endNode(builder, wrapped);
928→}
929→
930→function buildVectorPdfFromSvg(svgElement, paperSize) {
931→  const paper = getPaperPreset(paperSize);
932→  const pageWidthPt = paper.width * MM_TO_PT;
933→  const pageHeightPt = paper.height * MM_TO_PT;
934→  const builder = new PdfBuilder(pageWidthPt, pageHeightPt);
935→
936→  builder.write('q');
937→  builder.write(`${fmt(MM_TO_PT)} 0 0 ${fmt(-MM_TO_PT)} 0 ${fmt(pageHeightPt)} cm`);
938→  [...svgElement.children].forEach((child) => walkElement(builder, child));
939→  builder.write('Q');
940→
941→  return builder.finish();
942→}
943→
944→export async function exportActiveSheetAsPng(sheetTitle = 'sheet', options = {}) {
945→  const svgElement = getExportSvg();
946→  if (!svgElement) throw new Error('No sheet export source is available.');
947→  const { dpi = DEFAULT_PNG_DPI } = options;
948→  const { canvas } = await renderSvgToCanvas(svgElement, dpi);
949→
950→  await new Promise((resolve, reject) => {
951→    canvas.toBlob((blob) => {
952→      if (!blob) {
953→        reject(new Error('Failed to render PNG export.'));
954→        return;
955→      }
956→      downloadBlob(blob, `${sanitizeFileName(sheetTitle)}.png`);
957→      resolve();
958→    }, 'image/png');
959→  });
960→}
961→
962→export async function exportActiveSheetAsPdf(sheetTitle = 'sheet', paperSize = 'A3_LANDSCAPE') {
963→  const svgElement = getExportSvg();
964→  if (!svgElement) throw new Error('No sheet export source is available.');
965→  const pdfBlob = buildVectorPdfFromSvg(svgElement, paperSize);
966→  downloadBlob(pdfBlob, `${sanitizeFileName(sheetTitle)}.pdf`);
967→}
