280→      </div>
281→
282→      <div className={styles.dropdown} ref={toolMenuRef}>
283→        <button
284→          className={`${styles.btn} ${styles.dropdownTrigger}`}
285→          onClick={() => setToolMenuOpen(!toolMenuOpen)}
