895→function walkElement(builder, element) {
896→  const tagName = element.tagName.toLowerCase();
897→  const wrapped = beginNode(builder, element);
898→
899→  switch (tagName) {
900→    case 'svg':
901→    case 'g':
902→      [...element.children].forEach((child) => walkElement(builder, child));
903→      break;
904→    case 'rect':
905→      renderRect(builder, element);
906→      break;
907→    case 'line':
908→      renderLine(builder, element);
909→      break;
910→    case 'polygon':
911→      renderPolygonLike(builder, element, true);
912→      break;
913→    case 'polyline':
914→      renderPolygonLike(builder, element, false);
915→      break;
916→    case 'path':
917→      renderPath(builder, element);
918→      break;
919→    case 'text':
920→      renderText(builder, element);
921→      break;
922→    default:
923→      [...element.children].forEach((child) => walkElement(builder, child));
924→      break;
925→  }
926→
927→  endNode(builder, wrapped);
928→}
