932→  const pageWidthPt = paper.width * MM_TO_PT;
933→  const pageHeightPt = paper.height * MM_TO_PT;
934→  const builder = new PdfBuilder(pageWidthPt, pageHeightPt);
935→
936→  builder.write('q');
937→  builder.write(`${fmt(MM_TO_PT)} 0 0 ${fmt(-MM_TO_PT)} 0 ${fmt(pageHeightPt)} cm`);
